  1→import type { IncomingMessage, ServerResponse } from "node:http";
  2→import { initAgentMail, resetAgentMail } from "../agentmail";
  3→import {
  4→  getAgentById,
  5→  getDb,
  6→  getInboxSummary,
  7→  getRecentlyCancelledTasksForAgent,
  8→  getResolvedConfig,
  9→  getTaskById,
 10→  shouldBlockPolling,
 11→  updateAgentStatus,
 12→} from "../be/db";
 13→import { initGitHub, resetGitHub } from "../github";
 14→import { initLinear, resetLinear } from "../linear";
 15→import { startSlackApp, stopSlackApp } from "../slack";
 16→import type { AgentStatus } from "../types";
 17→import { generateOpenApiSpec, SCALAR_HTML } from "./openapi";
 18→import { agentWithCapacity, parseQueryParams } from "./utils";
 19→
 20→/**
 21→ * Load global swarm_config entries into process.env.
 22→ * When override=false (default, used at startup), existing env vars take precedence.
 23→ * When override=true (used for reload), DB values overwrite process.env.
 24→ * Returns the list of keys that were set/updated.
 25→ */
 26→export function loadGlobalConfigsIntoEnv(override = false): string[] {
 27→  const globalConfigs = getResolvedConfig();
 28→  const updated: string[] = [];
 29→  for (const config of globalConfigs) {
 30→    if (override || !process.env[config.key]) {
 31→      process.env[config.key] = config.value;
 32→      updated.push(config.key);
 33→    }
 34→  }
 35→  return updated;
 36→}
 37→
 38→export async function handleCore(
 39→  req: IncomingMessage,
 40→  res: ServerResponse,
 41→  myAgentId: string | undefined,
 42→  apiKey: string,
 43→): Promise<boolean> {
 44→  // Handle preflight
 45→  if (req.method === "OPTIONS") {
 46→    res.writeHead(204);
 47→    res.end();
 48→    return true;
 49→  }
 50→
 51→  if (req.url === "/health") {
 52→    // Read version from package.json
 53→    const version = (await Bun.file("package.json").json()).version;
 54→
 55→    res.writeHead(200, { "Content-Type": "application/json" });
 56→    res.end(
 57→      JSON.stringify({
 58→        status: "ok",
 59→        version,
 60→      }),
 61→    );
 62→
 63→    return true;
 64→  }
 65→
 66→  if (req.url === "/openapi.json") {
 67→    const version = (await Bun.file("package.json").json()).version;
 68→    const spec = generateOpenApiSpec({ version });
 69→    res.writeHead(200, { "Content-Type": "application/json" });
 70→    res.end(spec);
 71→    return true;
 72→  }
 73→
 74→  if (req.url === "/docs" || req.url === "/docs/") {
 75→    res.writeHead(200, { "Content-Type": "text/html" });
 76→    res.end(SCALAR_HTML);
 77→    return true;
 78→  }
 79→
 80→  // API key authentication (if API_KEY is configured)
 81→  // Skip auth for webhooks (they have their own signature verification)
 82→  const isGitHubWebhook = req.url?.startsWith("/api/github/webhook");
 83→  const isGitLabWebhook = req.url?.startsWith("/api/gitlab/webhook");
 84→  const isAgentMailWebhook = req.url?.startsWith("/api/agentmail/webhook");
 85→  const isLinearOAuth =
 86→    req.url?.startsWith("/api/linear/authorize") || req.url?.startsWith("/api/linear/callback");
 87→  if (apiKey && !isGitHubWebhook && !isGitLabWebhook && !isAgentMailWebhook && !isLinearOAuth) {
 88→    const authHeader = req.headers.authorization;
 89→    const providedKey = authHeader?.startsWith("Bearer ") ? authHeader.slice(7) : null;
 90→
 91→    if (providedKey !== apiKey) {
 92→      res.writeHead(401, { "Content-Type": "application/json" });
 93→      res.end(JSON.stringify({ error: "Unauthorized" }));
 94→      return true;
 95→    }
 96→  }
 97→
 98→  // POST /internal/reload-config — re-read swarm_config into process.env and re-init integrations
 99→  if (req.method === "POST" && req.url === "/internal/reload-config") {
100→    try {
101→      const updated = loadGlobalConfigsIntoEnv(true);
102→
103→      // Re-initialize integrations so they pick up new secrets
104→      const integrations: string[] = [];
105→
106→      resetAgentMail();
107→      if (initAgentMail()) integrations.push("agentmail");
108→
109→      resetGitHub();
110→      if (initGitHub()) integrations.push("github");
111→
112→      resetLinear();
113→      if (initLinear()) integrations.push("linear");
114→
115→      // Slack: stop and restart to pick up new token
116→      await stopSlackApp();
117→      await startSlackApp();
118→      integrations.push("slack");
119→
120→      console.log(
121→        `[reload-config] Loaded ${updated.length} config(s), re-initialized: ${integrations.join(", ") || "none"}`,
122→      );
123→
124→      res.writeHead(200, { "Content-Type": "application/json" });
125→      res.end(
126→        JSON.stringify({
127→          success: true,
128→          configsLoaded: updated.length,
129→          keysUpdated: updated,
130→          integrationsReinitialized: integrations,
131→        }),
132→      );
133→    } catch (e) {
134→      const message = e instanceof Error ? e.message : String(e);
135→      console.error("[reload-config] Failed:", message);
136→      res.writeHead(500, { "Content-Type": "application/json" });
137→      res.end(JSON.stringify({ error: "Failed to reload config", details: message }));
138→    }
139→    return true;
140→  }
141→
142→  if (req.method === "GET" && (req.url === "/me" || req.url?.startsWith("/me?"))) {
143→    if (!myAgentId) {
144→      res.writeHead(400, { "Content-Type": "application/json" });
145→      res.end(JSON.stringify({ error: "Missing X-Agent-ID header" }));
146→      return true;
147→    }
148→
149→    const agent = getAgentById(myAgentId);
150→
151→    if (!agent) {
152→      res.writeHead(404, { "Content-Type": "application/json" });
153→      res.end(JSON.stringify({ error: "Agent not found" }));
154→      return true;
155→    }
156→
157→    // Check for ?include=inbox query param
158→    const includeInbox = parseQueryParams(req.url || "").get("include") === "inbox";
159→
160→    // Add capacity info and polling limit check to agent response
161→    const agentResponse = {
162→      ...agentWithCapacity(agent),
163→      shouldBlockPolling: shouldBlockPolling(myAgentId),
164→    };
165→
166→    if (includeInbox) {
167→      const inbox = getInboxSummary(myAgentId);
168→      res.writeHead(200, { "Content-Type": "application/json" });
169→      res.end(JSON.stringify({ ...agentResponse, inbox }));
170→      return true;
171→    }
172→
173→    res.writeHead(200, { "Content-Type": "application/json" });
174→    res.end(JSON.stringify(agentResponse));
175→    return true;
176→  }
177→
178→  // GET /cancelled-tasks - Check for recently cancelled tasks (for hook cancellation detection)
179→  // Supports optional ?taskId= query param for checking specific task cancellation
180→  if (
181→    req.method === "GET" &&
182→    (req.url === "/cancelled-tasks" || req.url?.startsWith("/cancelled-tasks?"))
183→  ) {
184→    if (!myAgentId) {
185→      res.writeHead(400, { "Content-Type": "application/json" });
186→      res.end(JSON.stringify({ error: "Missing X-Agent-ID header" }));
187→      return true;
188→    }
189→
190→    const agent = getAgentById(myAgentId);
191→    if (!agent) {
192→      res.writeHead(404, { "Content-Type": "application/json" });
193→      res.end(JSON.stringify({ error: "Agent not found" }));
194→      return true;
195→    }
196→
197→    // Check for specific taskId query param
198→    const queryParams = parseQueryParams(req.url || "");
199→    const taskId = queryParams.get("taskId");
200→
201→    if (taskId) {
202→      // Check if specific task is cancelled
203→      const task = getTaskById(taskId);
204→      if (task && task.status === "cancelled") {
205→        res.writeHead(200, { "Content-Type": "application/json" });
206→        res.end(
207→          JSON.stringify({
208→            cancelled: [
209→              {
210→                id: task.id,
211→                task: task.task,
212→                failureReason: task.failureReason,
213→              },
214→            ],
215→          }),
216→        );
217→        return true;
