import { Database } from "bun:sqlite";
import type {
  ActiveSession,
  Agent,
  AgentLog,
  AgentLogEventType,
  AgentMemory,
  AgentMemoryScope,
  AgentMemorySource,
  AgentStatus,
  AgentTask,
  AgentTaskSource,
  AgentTaskStatus,
  AgentWithTasks,
  ChangeSource,
  Channel,
  ChannelMessage,
  ChannelType,
  ContextVersion,
  Epic,
  EpicStatus,
  EpicWithProgress,
  InboxMessage,
  InboxMessageStatus,
  ScheduledTask,
  Service,
  ServiceStatus,
  SessionCost,
  SessionLog,
  SwarmConfig,
  SwarmRepo,
  VersionableField,
  VersionMeta,
  Workflow,
  WorkflowDefinition,
  WorkflowRun,
  WorkflowRunStatus,
  WorkflowRunStep,
  WorkflowRunStepStatus,
} from "../types";
import { runMigrations } from "./migrations/runner";

let db: Database | null = null;

export function initDb(dbPath = "./agent-swarm-db.sqlite"): Database {
  if (db) {
    return db;
  }

  db = new Database(dbPath, { create: true });
  console.log(`Database initialized at ${dbPath}`);

  // Capture in local const for TypeScript (db is guaranteed non-null here)
  const database = db;

  database.run("PRAGMA journal_mode = WAL;");
  database.run("PRAGMA foreign_keys = ON;");

  // Run database migrations (schema creation + incremental changes)
  runMigrations(database);

