import { getDb } from "../db";
import type { OAuthApp, OAuthTokens } from "../../tracker/types";

// ── OAuth Apps ──

export function getOAuthApp(provider: string): OAuthApp | null {
  return getDb().query("SELECT * FROM oauth_apps WHERE provider = ?").get(provider) as OAuthApp | null;
}

export function upsertOAuthApp(
  provider: string,
  data: {
    clientId: string;
    clientSecret: string;
    authorizeUrl: string;
    tokenUrl: string;
    redirectUri: string;
    scopes: string;
    metadata?: string;
  },
): void {
  getDb()
    .query(
      `INSERT INTO oauth_apps (provider, clientId, clientSecret, authorizeUrl, tokenUrl, redirectUri, scopes, metadata)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)
       ON CONFLICT(provider) DO UPDATE SET
         clientId = excluded.clientId,
         clientSecret = excluded.clientSecret,
         authorizeUrl = excluded.authorizeUrl,
         tokenUrl = excluded.tokenUrl,
         redirectUri = excluded.redirectUri,
         scopes = excluded.scopes,
         metadata = excluded.metadata,
         updatedAt = datetime('now')`,
    )
    .run(
      provider,
      data.clientId,
      data.clientSecret,
      data.authorizeUrl,
      data.tokenUrl,
      data.redirectUri,
      data.scopes,
      data.metadata ?? "{}",
    );
}

// ── OAuth Tokens ──

export function getOAuthTokens(provider: string): OAuthTokens | null {
  return getDb().query("SELECT * FROM oauth_tokens WHERE provider = ?").get(provider) as OAuthTokens | null;
}

export function storeOAuthTokens(
  provider: string,
  data: {
    accessToken: string;
    refreshToken?: string | null;
    expiresAt: string;
    scope?: string | null;
  },
): void {
  getDb()
    .query(
      `INSERT INTO oauth_tokens (provider, accessToken, refreshToken, expiresAt, scope)
       VALUES (?, ?, ?, ?, ?)
       ON CONFLICT(provider) DO UPDATE SET
