      data.externalUrl ?? null,
      data.lastSyncOrigin ?? null,
      data.lastDeliveryId ?? null,
      data.syncDirection ?? "inbound",
    ) as TrackerSync;
  return result;
}

export function updateTrackerSync(
  id: string,
