async function main() {
  const port = 3014;
  const base = `http://localhost:${port}`;
  const headers = { "Authorization": "Bearer 123123" };

  // Status route (should be 503 - not configured)
  const status = await fetch(`${base}/api/trackers/linear/status`, { headers });
  console.log(`Status route: ${status.status} (expect 503)`);

  // Authorize route (should be 503 - not configured)  
  const auth = await fetch(`${base}/api/trackers/linear/authorize`, { redirect: "manual" });
  console.log(`Authorize route: ${auth.status} (expect 503)`);

  // Webhook without signature (should be 401 or 503)
  const webhook = await fetch(`${base}/api/trackers/linear/webhook`, { method: "POST", body: "{}", headers: { "Content-Type": "application/json" } });
  console.log(`Webhook (no sig): ${webhook.status} (expect 401 or 503)`);

  // Old route (should be 404)
  const old = await fetch(`${base}/api/linear/authorize`, { headers });
  console.log(`Old /api/linear/authorize: ${old.status} (expect 404)`);

  // OpenAPI check
  const spec = await fetch(`${base}/openapi.json`, { headers }).then(r => r.json());
  const trackerPaths = Object.keys(spec.paths).filter(p => p.includes("trackers"));
  console.log(`OpenAPI tracker routes (${trackerPaths.length}): ${trackerPaths.join(", ")}`);
}
main().catch(e => console.error(e.message));
'

