import { cancelTask, createTaskExtended, getAllAgents, getTaskById } from "../be/db";
import { getOAuthTokens } from "../be/db-queries/oauth";
import {
  createTrackerSync,
  getTrackerSyncByExternalId,
  updateTrackerSync,
} from "../be/db-queries/tracker";

/**
 * Update a Linear AgentSession status via the GraphQL API.
 * The @linear/sdk doesn't support AgentSession yet, so we call the API directly.
 */
async function updateAgentSessionStatus(
  sessionId: string,
  status: "active" | "completed" | "failed",
): Promise<void> {
  const tokens = getOAuthTokens("linear");
  if (!tokens) {
    console.log("[Linear Sync] No OAuth tokens, cannot update AgentSession status");
    return;
  }

  const mutation = `
    mutation AgentSessionUpdate($id: String!, $input: AgentSessionUpdateInput!) {
      agentSessionUpdate(id: $id, input: $input) {
        success
      }
    }
  `;

  const res = await fetch("https://api.linear.app/graphql", {
    method: "POST",
    headers: {
      "Content-Type": "application/json",
      Authorization: `Bearer ${tokens.accessToken}`,
    },
    body: JSON.stringify({
      query: mutation,
      variables: { id: sessionId, input: { status } },
    }),
  });

  if (!res.ok) {
    console.error(`[Linear Sync] Failed to update AgentSession ${sessionId}: ${res.status} ${res.statusText}`);
    return;
  }

  const result = (await res.json()) as { data?: { agentSessionUpdate?: { success: boolean } }; errors?: unknown[] };
  if (result.errors) {
    console.error("[Linear Sync] GraphQL errors updating AgentSession:", result.errors);
    return;
  }

  console.log(`[Linear Sync] AgentSession ${sessionId} status → ${status}`);
}

